module top_module(
    inverse_direction,
    shiftin,
    shiftby,
    shiftout
);input inverse_direction;
input signed [25:0] shiftin;
input [4:0] shiftby;
output reg signed [25:0] shiftout;

always @(*) begin
    if (inverse_direction == 1) begin
        shiftout = shiftin >>> shiftby;
    end else begin
        shiftout = shiftin << shiftby;
    end
end

endmodule
